      <text x="40" y="131" fill="#e4e4e7" font-size="14">30 años</text>
      <rect x="115" y="117" width="343" height="26" rx="4" fill="#0ea5e9"/>
      <text x="468" y="135" fill="#0ea5e9" font-size="14" font-weight="700">3,43% (récord)</text>
      <line x1="20" y1="168" x2="680" y2="168" stroke="#3f3f46" stroke-width="1"/>
